  @state layouts = {  @ 16
  @state chars = {}  @ 35
  @state mgr = {  @ 49
  @state global = newScope()  @ 117
  @state prefixBuf, pendingPrefix = nil, nil  @ 179
  @state pendingPrefixNum, pendingPrefixDen = nil, nil  @ 180

